var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"너…… 여기까지 어떻게……?","JPN":"お前……どうやってここまで……？","ENG":"You...? But how...?","TWN":"你……怎麼會來這裡……？"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그라운드 원으로 도주한 카운터 범죄자들을 체포하는 것도 우리 일이야.","JPN":"グラウンド・ワンに逃走したカウンターの犯罪者を逮捕するのも私たちの仕事なの。","ENG":"It's our job to arrest Criminal Counters who have fled to Ground One.","TWN":"逮補逃到G1的制裁者罪犯也是我們的職責所在。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그리고 여기, 코핀 컴퍼니는 사건 해결을 위해 협조한 적 있는 태스크포스고.","JPN":"それにここ、コフィンカンパニーは事件の解決のために協力したことがあるタスクフォースだし。","ENG":"And this TASKFORCE, Coffin Company, has cooperated with us in solving some cases.","TWN":"況且，這裡是曾經協助解決科芬公司事件的特遣勢力。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"신고가 들어오면 관심을 가질 수밖에 없지. 나나, 경위나.","JPN":"通報が入れば注意が向くのよ。私も、警部補も。","ENG":"When a report about this place comes in, the lieutenant and I can't help but pay attention.","TWN":"有人報警的話，不管是我或是姜素英員警，當然都必須來關心一下。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……코핀 컴퍼니. 그 용병들 회사였지.","JPN":"……コフィンカンパニー。あの傭兵たちの会社だったな。","ENG":"...Coffin Company. That's gotta be those mercs.","TWN":"……科芬公司，是那些傭兵的公司對吧？"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"레비아는? 승강기를 지키고 있었을 텐데?","JPN":"レヴィアは？　エレベーターを見張ってたはずだが？","ENG":"What about Levia? Isn't she supposed to be guarding the elevator?","TWN":"莉維亞呢？她不是該守著電梯嗎？"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"지금 당신들 공범이 어디 있는지 나한테 물어 보는 거야?","JPN":"今あなたたちの共犯がどこにいるのか、私に聞くわけ？","ENG":"Are you asking me where your accomplice is?","TWN":"你現在是在問我，你們的共犯在哪裡嗎？"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……레비아, 마지막까지 사고를 치는군.","JPN":"……レヴィア、最後までやらかしてくれるな。","ENG":"Levia, you had one job...","TWN":"……莉維亞，到最後還是在惹麻煩。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"총에 맞았던 형사는 무사한가?","JPN":"銃に撃たれた刑事は無事か？","ENG":"How's the cop who got shot? Is she doing well?","TWN":"中槍的警察沒事吧？"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"목숨은 건졌어. 언제 죽을지 모르는 상태지만.","JPN":"命はあるわ。いつ死ぬかわからない状態だけど。","ENG":"She's alive. If barely.","TWN":"是撿回一條命，只是不知道什麼時候會死。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"공무 수행 중인 경찰을 공격한 이상, 각오는 됐겠지?","JPN":"公務執行中の警察官を攻撃した以上、覚悟はできてるでしょうね？","ENG":"You know what's coming for you since you attacked an officer on duty, right?","TWN":"你們既然敢襲擊執勤的員警，應該就有做好心理準備吧？"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……변명은 하지 않겠다. 경찰을 해쳤으면 대가를 치러야지.","JPN":"……言い訳はしない。警察官を怪我させたんだ、償いはしないとな。","ENG":"...I have no excuse. I'll pay the price for my actions.","TWN":"……我不打算辯解，傷害警察就該付出代價。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지만 우리는 이 일을 끝내야 해. 그 뒤에는 그쪽 마음대로 해라.","JPN":"だが俺たちはこの仕事を終わらせないといけないんだ。その後はそっちの勝手にしろ。","ENG":"But there's a job we need to finish. After that, I'll do as I'm told.","TWN":"但我們必須先解決這件事，決解完後就都聽你的。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"누가 당신 말대로 할 줄 알아?! 명령하지 마!","JPN":"あなたの言うとおりになんかすると思う？！　命令しないで！","ENG":"Who're you to tell me what to do, huh?! Don't order me around!","TWN":"你以為我會聽你的嗎？！少命令我！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"으윽……?!","JPN":"ううっ……！？","ENG":"Ugh...?!","TWN":"唔唔……？！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L28_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"잡았다, 이 범죄자!","JPN":"捕まえた！　この犯罪者！","ENG":"You're mine now, criminal!","TWN":"束手就擒吧！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장!?","JPN":"隊長！？","ENG":"Captain?!","TWN":"隊長！？"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장은 부상 입은 상태야! 죽이기라도 할 작정이야?!","JPN":"隊長は怪我人なんだぞ！　殺す気か！？","ENG":"Captain's injured right now! Are you trying to kill him?!","TWN":"隊長現在身負重傷！你是想要他的命嗎？！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그게 뭐!! 체포에 불응해 놓고 엄살 부리지 마!","JPN":"それが何だって言うの！！　逮捕に応じなかったくせに、つべこべ言わないで！","ENG":"So what?! You're the one who resisted arrest, so don't overreact!","TWN":"那又怎樣！！你們不乖乖就範還想求情嗎！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"자수해도 소용없어! 그러기엔 이미 한참 늦었으니까!","JPN":"自首しても無駄よ！　もう遅い！","ENG":"It's no use turning yourselves in now! It's too late for that!","TWN":"自首也沒用！現在已經為時已晚！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"이유미, 너…….","JPN":"カスカベ・ユミ、お前……","ENG":"Lee Yumi, why you...","TWN":"李悠美，你……"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"……최초 신고자의 증언으로 피해자에 대한 자료를 손에 넣었어.","JPN":"……最初の通報者の証言で被害者についての資料を手に入れたわ。","ENG":"...I got the data on the victim through the first witness's testimony.","TWN":"……我有根據一開始報案人的證言，得到受害者有關的資料。"},"stage":{"bg":"SS_MAID_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"베로니카. 반사회적 암살 조직의 암살자 출신.","JPN":"ベロニカ。反社会的な暗殺組織の元暗殺者。","ENG":"Veronica. Former assassin for an antisocial assassination organization.","TWN":"貝洛妮卡，原是反社會暗殺組織的殺手，"},"stage":{"bg":"SS_MAID_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"하지만 지금은 사법 거래를 통해 증인 보호 프로그램 대상자가 된 상태야.","JPN":"でも今は司法取引を通じて証人保護プログラムの対象者になっている状態よ。","ENG":"However, she's currently in witness protection after taking a plea bargain.","TWN":"現在因為司法交易而成為證人保護項目的對象。"},"stage":{"bg":"SS_MAID_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……적당히 해, 꼬마 경찰관.","JPN":"……いい加減にしろ、ひよっこ警察官。","ENG":"…Cool it, little cop missy.","TWN":"……說夠沒有，警察大人！"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"사법거래라고? 죗값을 치렀어?","JPN":"司法取引？　罪滅ぼし？","ENG":"A plea bargain? So she paid the price for her sins?","TWN":"司法交易？他有付上代價嗎？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"피해자는 용서하지도 않았는데 누가 용서해 준다는 거야?","JPN":"被害者は許してないのに誰が許すんだ？","ENG":"How can she be forgiven if even the victims haven't forgiven her yet?!","TWN":"受害者又沒原諒她，你說誰原諒她？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"네가 떠드는 그 법이 죽은 사람들을, 남겨진 사람들을 신경이나 써 줄 것 같아?","JPN":"お前の言うその法が、死んだ人たちを、残された人たちを気にかけてくれるとでもいうのか？","ENG":"That law you uphold, does it even take into account those who are left behind?","TWN":"你嘴巴說的法律，有顧慮到死去的人，或是留下人的嗎？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"이미 죄를 지은 놈들을 갱생시킨다고? 사회에 공헌할 수 있게 기회를 줘?","JPN":"罪を犯したやつらを更生させるだと？　社会に貢献できるように機会を与える？","ENG":"Rehabilitating sinners? Giving them a chance to contribute to society?!","TWN":"讓犯罪的人有更生的機會？向社會貢獻的機會？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그딴 건…… 그딴 건 당해 본 적도 없고, 당할 리도 없는 놈들이나 하는 소리야!","JPN":"そんなのは……そんなのはやられたことも、やられるはずもないやつらのいうことだ！","ENG":"That... That's what people who have not and will not suffer from anything like this say!","TWN":"這些話……這些話是那些沒遭遇過的人，或是沒機會遭遇到的人在說的！"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"변론은 거기까지야?","JPN":"弁論はそれで終わり？","ENG":"Is that the end of your argument?","TWN":"你要說的就這些嗎？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"뭐?","JPN":"は？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"민병대는 카운터 범죄자만을 노린다며?","JPN":"民兵隊はカウンターの犯罪者だけを狙うんだってね。","ENG":"Doesn't the Militia only go after Criminal Counters?","TWN":"你說民兵隊只針對制裁者罪犯？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"민간인들은 건드리지 않는다고 옹호하는 바보들도 있었지.","JPN":"民間人には手を出さないからって擁護するバカもいるのよね。","ENG":"That's why some idiots defend you. Because you don't harm civilians.","TWN":"還有一群傻瓜，因為你們說不會碰老百姓就支持你們是吧？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……우린 계속 그래왔어. 그게 어쨌다는 거지?","JPN":"……私たちはずっとそうやってきた。それがどうした？","ENG":"...That's what we've always been doing. So what?","TWN":"……我們一直是這樣，你想說什麼？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"하지만 당신들은 이번에 보안 업체에 피해를 입힌 데다 민간인 협력자까지 살해했어.","JPN":"でもあなたたちは今回セキュリティー会社に被害を与えた上に、民間人の協力者まで殺害した。","ENG":"But this time, you caused damage to a security company, and even got a civilian cooperator killed.","TWN":"你們這次不僅讓保安業者受到損失，甚至還殺害無辜的百姓。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그건 사고였어!","JPN":"それは事故だったんだ！","ENG":"That was an accident!","TWN":"那是個意外！"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"사고? 그럼 도심 한복판에서 경찰을 저격한 것도 사고라고 우길 거야?!","JPN":"事故？　じゃあ、都心の真ん中で警察官を狙撃したのも事故だって主張するつもり！？","ENG":"An accident, eh? What? Are you going to argue that sniping a police officer was also \\"an accident\\"?","TWN":"意外？所以在市中心槍擊警察也是意外嗎？！"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그건……!","JPN":"それは……！","ENG":"That’s...!","TWN":"那是……！"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"알파트릭스 관계자에게 다 들었어. 당신 카운터라며?","JPN":"アルファトリックスの関係者から全部聞いたわ。あなた、カウンターなんだってね？","ENG":"I heard it all from Alphatrix. You're a Counter, aren't you?","TWN":"我聽阿爾法崔克斯的關係人說你是制裁者？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"자기 입맛대로 법을 무시하고, 카운터 능력으로 사회를 혼란에 빠뜨리고.","JPN":"自分勝手に法を無視して、カウンターの能力で社会に混沌を持ち込んで。","ENG":"You're the one fueling chaos in the streets by using your abilities and disregarding laws as you see fit.","TWN":"自己藐視法律，卻利用制裁者的能力使社會陷入混亂，"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"남이 저지른 살인죄는 용서 못하고 자기가 불법무기를 쓰는 건 어쩔 수 없는 선택이야?","JPN":"人が犯した殺人罪は許せないくせに、自分が不法武器を使ってるのはやむを得ないっていうの？","ENG":"So you can't forgive someone else for murdering, but you also have no choice but to use illegal weapons?","TWN":"嘴巴上說無法原諒別人犯下殺人罪，自己卻使用非法武器，這些都是不得已的嗎？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……적당히 해.","JPN":"……いい加減にしろ。","ENG":"...Watch it.","TWN":"……你說夠沒有！"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"유리할 때는 폭력을 휘두르고 다니지! 불리하면 피해자 행세를 하고!","JPN":"有利な時には暴力を振り回す！　不利になれば被害者のふりをする！","ENG":"You use violence when it fits you, but now you're the victim here?!","TWN":"對自己有利的時候就濫用暴力！對自己不利的時候裝得一副受害者的樣子！"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"적당히 해, 이유미……!","JPN":"いい加減にしろよ、カスカベ・ユミ……！","ENG":"Damm...! I said watch it...!","TWN":"夠囉，李悠美……！"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"아직도 모르겠어?!","JPN":"まだわからないの！？","ENG":"You still don't get it, do you?","TWN":"你還搞不清楚嗎？！"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"지금 당신들 꼴이 대체 카운터 범죄자들과 뭐가 달라!","JPN":"今あなたたちのやってることと、カウンターの犯罪者のやってたことと何が違うのよ！","ENG":"What you guys are doing is the same thing as those other Criminal Counters!","TWN":"現在的你們，和那些制裁者罪犯到底有什麼不同！"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"너는……","JPN":"お前は……","ENG":"No...","TWN":"你……"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"적어도 너만큼은! 그렇게 말해선 안 돼!!","JPN":"少なくともお前だけは！　それを言うな！！","ENG":"You shouldn't say that! Not you!!","TWN":"其他人可以，但你！不可以這麼說！！"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"난 민병대도 싫고 대장도 엿 같았지만...... 사실 네가 제일 싫었어.","JPN":"俺は民兵隊も隊長も嫌いだったが……お前のことが一番嫌いだった。","ENG":"I hated the Militia and the Captain... but I hated you the most.","TWN":"我討厭民兵隊，也討厭隊長……但最討厭的人是你。"},"stage":{"bg":"HALL","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"뭐야?!","JPN":"何だと！？","ENG":"What?","TWN":"什麼？！"},"stage":{"bg":"HALL","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"왜냐하면...... 넌 정말 예전의 나를 보는 것 같았거든.","JPN":"……お前を見ていると、昔の自分を見ている気がしたからな。","ENG":"Because... you reminded me of my younger self.","TWN":"因為……你和從前的我像極了。"},"stage":{"bg":"HALL","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"민병대라는 곳은 차라리 빨리 죽는 게 살아남는 것 보다 나을 때가 있어.","JPN":"民兵隊にいると、生き残るよりもいっそ早く死んだ方がマシだと思うことが多い。","ENG":"Sometimes it's better to die first than survive when you're in the Militia.","TWN":"在民兵隊，很多時候生不如死。"},"stage":{"bg":"HALL","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그래서? 날 죽여줄 테니까 감사라도 하라는 거야?","JPN":"それで？　殺してやるから感謝しろって？","ENG":"So what? Are you saying I should be grateful because you'll whack me?","TWN":"所以呢？我得感謝你殺我之恩？"},"stage":{"bg":"HALL","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"아니.","JPN":"いや。","ENG":"No.","TWN":"不是。"},"stage":{"bg":"HALL","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"혹시라도 안 죽고 너무 오래 살아남으면......","JPN":"もし死ぬことができずに、長生きでもしちまったら……","ENG":"I'm just saying if you happen to survive long enough...","TWN":"如果你不小心活了太久……"},"stage":{"bg":"HALL","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"나처럼 추해지기 전에 미리미리 은퇴할 자리를 찾아두라고.","JPN":"俺みたいに墜ちるところまで墜ちる前に、さっさと引退しろってことだ。","ENG":"Find a better retirement option before you hit rock bottom like me.","TWN":"就好好準備退役，別像我一樣落到這種地步。"},"stage":{"bg":"HALL","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"여태까지 자기 내킬 대로 폭주하면 만사가 잘 풀리는 줄 알았겠지!","JPN":"今まで心の赴くままに暴走すればすべてがうまく行くって思っていたんでしょ！","ENG":"You thought that everything would work out the way you wanted to, didn't you?","TWN":"到現在為止，你都以為你的任意妄為可以解決任何事對吧！"},"stage":{"bg":"MS_1003","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_POLICE_LEE_YUMI_IN_TRAILER_1"},{"id":"L38_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"각오해!! 이번엔 다를 테니까!","JPN":"覚悟しなさい！！　今度は違うから！","ENG":"Well, not this time!","TWN":"覺悟吧！這次可不一樣！"},"stage":{"bg":"MS_1003","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_POLICE_LEE_YUMI_IN_TRAILER_2"},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"미안해, 최지훈.","JPN":"ごめん、ゴトウ。","ENG":"I'm sorry, Jihoon...","TWN":"崔智勳，對不起。"},"stage":{"bg":"MS_1003","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"네가 했던 말. 좀 더 귀담아 들을 걸 그랬어.","JPN":"話、ちゃんと聞いておけばよかった。","ENG":"I should've listened more carefully to what you said.","TWN":"你說的話，我應該更認真聽的。"},"stage":{"bg":"MS_1003","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};